// ---- Adaptive Layouts ----
// Responsive layouts that adapt to screen size

// ---- Window size classes ----
@Composable
fun AdaptiveLayout() {
    val configuration = LocalConfiguration.current
    val screenWidth = configuration.screenWidthDp

    // ---- Determine layout type ----
    when {
        screenWidth < 600 -> CompactLayout()
        screenWidth < 840 -> MediumLayout()
        else -> ExpandedLayout()
    }
}

// ---- Compact layout (phone) ----
@Composable
fun CompactLayout() {
    Scaffold(
        topBar = { TopAppBar { Text("Compact Layout") } },
        bottomBar = { BottomNavBar() }
    ) { paddingValues ->
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(10) { index ->
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text("Item ${index + 1}")
                        Text(
                            text = "Description of item ${index + 1}",
                            style = MaterialTheme.typography.bodyMedium
                        )
                    }
                }
            }
        }
    }
}

// ---- Medium layout (tablet) ----
@Composable
fun MediumLayout() {
    Scaffold(
        topBar = { TopAppBar { Text("Medium Layout") } }
    ) { paddingValues ->
        Row(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
        ) {
            // Navigation rail
            NavigationRail(
                modifier = Modifier
                    .fillMaxHeight()
                    .width(72.dp)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(8.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    NavigationRailItem(
                        icon = { Icon(Icons.Default.Home, null) },
                        selected = true,
                        onClick = {}
                    )
                    NavigationRailItem(
                        icon = { Icon(Icons.Default.Search, null) },
                        selected = false,
                        onClick = {}
                    )
                    NavigationRailItem(
                        icon = { Icon(Icons.Default.Person, null) },
                        selected = false,
                        onClick = {}
                    )
                    NavigationRailItem(
                        icon = { Icon(Icons.Default.Settings, null) },
                        selected = false,
                        onClick = {}
                    )
                }
            }

            // Content
            Grid(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(16.dp),
                columns = 2,
                verticalArrangement = Arrangement.spacedBy(8.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                repeat(10) { index ->
                    Card(
                        modifier = Modifier.height(120.dp),
                        elevation = CardDefaults.cardElevation(4.dp)
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(16.dp),
                            verticalArrangement = Arrangement.Center,
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text("Item ${index + 1}")
                        }
                    }
                }
            }
        }
    }
}

// ---- Expanded layout (large tablet/desktop) ----
@Composable
fun ExpandedLayout() {
    Scaffold(
        topBar = { TopAppBar { Text("Expanded Layout") } }
    ) { paddingValues ->
        Row(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
        ) {
            // Permanent drawer
            NavigationRail(
                modifier = Modifier
                    .fillMaxHeight()
                    .width(240.dp)
                    .padding(16.dp)
            ) {
                Column(
                    modifier = Modifier.fillMaxSize(),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Text(
                        text = "Menu",
                        style = MaterialTheme.typography.titleLarge
                    )
                    Divider()

                    // Menu items
                    listOf("Home", "Search", "Profile", "Settings").forEach { label ->
                        Button(
                            onClick = {},
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Text(label)
                        }
                    }

                    Divider()
                    Text(
                        text = "Footer",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            // Main content
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(16.dp)
            ) {
                Text(
                    text = "Main Content",
                    style = MaterialTheme.typography.headlineMedium
                )
                Spacer(modifier = Modifier.height(16.dp))

                Grid(
                    columns = 4,
                    verticalArrangement = Arrangement.spacedBy(8.dp),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    repeat(12) { index ->
                        Card(
                            modifier = Modifier.height(100.dp),
                            elevation = CardDefaults.cardElevation(4.dp)
                        ) {
                            Box(
                                modifier = Modifier.fillMaxSize(),
                                contentAlignment = Alignment.Center
                            ) {
                                Text("Item ${index + 1}")
                            }
                        }
                    }
                }
            }
        }
    }
}

// ---- BottomNavBar (for compact layout) ----
@Composable
fun BottomNavBar() {
    NavigationBar {
        listOf("Home", "Search", "Profile").forEach { label ->
            NavigationBarItem(
                icon = { Icon(Icons.Default.Home, null) },
                label = { Text(label) },
                selected = label == "Home",
                onClick = {}
            )
        }
    }
}

// ---- Window size classes helper ----
@Composable
fun AdaptiveContent(
    compactContent: @Composable () -> Unit,
    mediumContent: @Composable () -> Unit,
    expandedContent: @Composable () -> Unit
) {
    val configuration = LocalConfiguration.current
    val screenWidth = configuration.screenWidthDp

    when {
        screenWidth < 600 -> compactContent()
        screenWidth < 840 -> mediumContent()
        else -> expandedContent()
    }
}

