package com.example.adaptive

import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalConfiguration
import androidx.compose.ui.unit.dp

@Composable
fun AdaptiveLayoutDemo() {
    val configuration = LocalConfiguration.current
    val screenWidth = configuration.screenWidthDp

    val items = (1..12).map { "Item $it" }

    Scaffold(
        topBar = { TopAppBar { Text("Adaptive Layout") } }
    ) { paddingValues ->
        when {
            screenWidth < 600 -> CompactList(items, paddingValues)
            else -> ExpandedGrid(items, paddingValues)
        }
    }
}

@Composable
fun CompactList(items: List<String>, paddingValues: PaddingValues) {
    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(paddingValues),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        items(items) { item ->
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp),
                elevation = CardDefaults.cardElevation(4.dp)
            ) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(60.dp)
                        .padding(16.dp),
                    contentAlignment = Alignment.CenterStart
                ) {
                    Text(item, style = MaterialTheme.typography.titleMedium)
                }
            }
        }
    }
}

@Composable
fun ExpandedGrid(items: List<String>, paddingValues: PaddingValues) {
    val columns = when {
        LocalConfiguration.current.screenWidthDp < 840 -> 2
        else -> 3
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(paddingValues)
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        // Simple grid implementation
        items.chunked(columns).forEach { rowItems ->
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                rowItems.forEach { item ->
                    Card(
                        modifier = Modifier
                            .weight(1f)
                            .height(80.dp),
                        elevation = CardDefaults.cardElevation(4.dp)
                    ) {
                        Box(
                            modifier = Modifier.fillMaxSize(),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(item, style = MaterialTheme.typography.titleMedium)
                        }
                    }
                }
                // Fill remaining columns
                repeat(columns - rowItems.size) {
                    Spacer(modifier = Modifier.weight(1f))
                }
            }
        }
    }
}
